class Solution {
public:
    int compress(vector<char>& chars) {
        int n = chars.size();
        int write = 0, anchor = 0;
        for (int read = 0; read < n; ++read) {
            if (read == n - 1 || chars[read + 1] != chars[read]) {
                chars[write++] = chars[anchor];
                if (read > anchor) {
                    for (char c : to_string(read - anchor + 1)) {
                        chars[write++] = c;
                    }
                }
                anchor = read + 1;
            }
        }
        return write;
    }
};
